const body = $input.first().json.body || {};
const complaintId     = parseInt(body.complaintId);
const closureStatus   = (body.closureStatus  || 'Partially Closed');
const followupMethod  = (body.followupMethod || 'Call');
const txnId           = body.txnId          || '';
const mobileCalled    = body.mobileCalled   || '';
const emailSubject    = body.emailSubject   || '';
const vendorTicketNo  = (body.vendorTicketNo || '').trim();
const delayMain       = body.delayMain      || '';
const delaySub        = body.delaySub       || '';
const baseRemarks     = body.remarks        || '';
const uid             = parseInt(body.uid   || 1);
const escalationLevel = parseInt(body.escalationLevel || 1);
const newClosureDate  = body.newClosureDate || '';
const closureDate     = body.closureDate    || '';
const closedBy        = (body.closedBy      || '').trim();

if (!complaintId) return [{ json: { success: false, error: 'complaintId required' } }];

const esc = v => (v || '').toString().replace(/'/g, "''");

const parts = [baseRemarks];
if (followupMethod === 'Call') {
  if (txnId) parts.push('TXN: ' + txnId);
  if (mobileCalled) parts.push('Mobile: ' + mobileCalled);
} else if (followupMethod === 'Vendor Update') {
  if (vendorTicketNo) parts.push('Vendor Ticket: ' + vendorTicketNo);
} else {
  if (emailSubject) parts.push('Subject: ' + emailSubject);
}
if (delayMain) parts.push('Delay: ' + delayMain + (delaySub ? ' - ' + delaySub : ''));
if (closureDate) parts.push('Closure Date: ' + closureDate);
if (closedBy) parts.push('Closed By: ' + closedBy);
parts.push('Source: ' + followupMethod);

const fullRemarks = esc(parts.filter(Boolean).join(' | '));

const insertLog = `INSERT INTO vmm_complaintlogs (complaintid, remarks, status, uid, created, is_deleted) VALUES (${complaintId}, '${fullRemarks}', '${esc(closureStatus)}', ${uid}, NOW(), 'No')`;

const insertEsc = ((closureStatus === 'Partially Closed' || closureStatus === 'Escalated') && newClosureDate)
  ? `INSERT INTO vmm_vendorescalations (complaintid, escalationlevel, ticketno, closuredate, uid, created, is_deleted) VALUES (${complaintId}, ${escalationLevel}, '${esc(vendorTicketNo)}', '${esc(newClosureDate)}', ${uid}, NOW(), 'No')`
  : null;

const updateTicket = (vendorTicketNo && closureStatus !== 'Partially Closed' && closureStatus !== 'Escalated')
  ? `UPDATE vmm_vendorescalations SET ticketno = '${esc(vendorTicketNo)}' WHERE id = (SELECT MAX(id) FROM vmm_vendorescalations WHERE complaintid = ${complaintId})`
  : null;

return [{ json: { insertLog, insertEsc, updateTicket, complaintId, closureStatus } }];
